-- W1.6 questions batch 8872/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('pukao-e0adf6cd-moex-00126', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-112-6025795a', 'sub-pukao-e0adf6cd-05', NULL, 'essay', '假設有一位心理學家想籌建一套測驗評量系統，作為未來升學或就業時
的診斷評估與甄選之用，並擬由各種不同心理測驗工具所組成。請問：你
會建議他該考量什麼因素作為挑選測驗工具之參考標準？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:37+00:00", "source_pdf_sha1": "e6ae401d1c77", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "408", "s": "0606", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育測驗與統計概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL),
  ('pukao-e0adf6cd-moex-00127', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-112-6025795a', 'sub-pukao-e0adf6cd-05', NULL, 'essay', '某國小六年級學生的英語文檢測成績，剛好呈現常態分配的結果；此時，
平均數、中位數及眾數等三種集中量數的數值，剛好都會相等。由於該校
地處都市與偏鄉的交界處，後來因為發生下列事故情境，導致該校英語文
成績的次數分配開始產生變化：
情境：由於當地政府正在積極整頓當地的交通問題，一時之間，交通陷
入黑暗期，導致該校英語文成績優異的學生紛紛轉出至鄰近都市裡的學
校就讀。請問：此時，該校英語文檢測成績的次數分配，將會呈現何種偏
態的次數分配？（5分）在該種偏態的次數分配中，平均數、中位數及眾
數等三種集中量數，何者的數值將會最大？（5分）
情境：一段時間後，當地政府整頓交通問題完畢，當地交通變得十分通
暢。該校校長為挽救該校的就學率，大力推動雙語教育政策，反而吸引鄰
近都市與偏鄉學校中英語文高材生紛紛轉入該校就讀，甚至，連當初轉學
出去的高材生也全部紛紛回籠轉學回來就讀。請問：此時，該校英語文檢
測成績的次數分配，將會呈現何種偏態的次數分配？（5分）在該種偏態
的次數分配中，平均數、中位數及眾數等三種集中量數，何者的數值將會
最大？（5分）
情境：經過上述兩種情境的干擾影響後，該校校長終將發現，在該校英
語文檢測成績的次數分配中，有一種集中量數始終都會介於另兩種集中
量數之間。請問：它會是何種集中量數？（5分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:37+00:00", "source_pdf_sha1": "e6ae401d1c77", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "408", "s": "0606", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育測驗與統計概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL),
  ('pukao-e0adf6cd-moex-00128', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-112-6025795a', 'sub-pukao-e0adf6cd-05', NULL, 'essay', '某教授觀察到教育統計學的學習成績，似乎存在著性別差異，且多數文獻
均顯示男性學生的成績遠優於女性學生的成績。請問：你會建議他採用何
種統計分析方法來驗證所觀察到的現象，並說明此檢驗的步驟？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:37+00:00", "source_pdf_sha1": "e6ae401d1c77", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "408", "s": "0606", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "教育測驗與統計概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL),
  ('pukao-e0adf6cd-moex-00129', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-112-d1a761c9', 'sub-pukao-e0adf6cd-03', NULL, 'single_choice', '下列何者非屬成文法法源？', '["議會自律規則", "國際條約", "一般法律原則", "行政規則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:37+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "408", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL),
  ('pukao-e0adf6cd-moex-00130', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-112-d1a761c9', 'sub-pukao-e0adf6cd-03', NULL, 'single_choice', '關於法規命令之訂定與生效，下列敘述何者錯誤？', '["法規命令依法應經上級機關核定者，於核定後始得發布", "法規命令之發布，應刊登於政府公報或新聞紙", "任何人得於公告期間內針對法規命令之草案提出意見", "法規命令乃行政權行使，受司法違憲之審查，惟不受立法權之審查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:37+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "408", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL),
  ('pukao-e0adf6cd-moex-00131', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-112-d1a761c9', 'sub-pukao-e0adf6cd-03', NULL, 'single_choice', '下列何者非屬行政程序法明定之一般法律原則？', '["對等互惠原則", "誠實信用原則", "比例原則", "平等原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:37+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "408", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL),
  ('pukao-e0adf6cd-moex-00132', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-112-d1a761c9', 'sub-pukao-e0adf6cd-03', NULL, 'single_choice', '行政機關對於法律構成要件之涵攝，除有明顯瑕疵外，行政法院應予尊重之情形，為下列何者？', '["裁量收縮至零", "裁量瑕疵", "判斷餘地", "計畫裁量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:37+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "408", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL),
  ('pukao-e0adf6cd-moex-00133', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-112-d1a761c9', 'sub-pukao-e0adf6cd-03', NULL, 'single_choice', '關於給付行政之敘述，下列何者正確？', '["給付行政全屬公權力之行使，均為公法事件", "農民健康保險之給付事項屬給付行政，為公法事件", "給付行政與干涉行政相同，均受嚴格之法律保留原則所拘束", "金融機構辦理清寒學生助學貸款，屬公法性質之給付行政"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:37+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "408", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL),
  ('pukao-e0adf6cd-moex-00134', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-112-d1a761c9', 'sub-pukao-e0adf6cd-03', NULL, 'single_choice', '某公立高中學生無照騎乘機車，受記大過一次之處分。其不服時，依司法院大法官解釋，得提起何種之救濟？', '["得依法提起相應之行政爭訟程序", "因非屬退學或類此之處分，故不得提起救濟", "只得依循校內救濟途徑提起救濟", "應依民事程序請求救濟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:37+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "408", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL),
  ('pukao-e0adf6cd-moex-00135', 'pukao-e0adf6cd', 'pukao-e0adf6cd-moex-112-d1a761c9', 'sub-pukao-e0adf6cd-03', NULL, 'single_choice', '關於行政法人之概念，下列敘述何者錯誤？', '["行政法人所涉及公權力程度較低", "係為執行特定公共事務，依法律設立之公法人", "行政法人之經費必須全數自籌", "人民對於行政法人所為行政處分不服，應向監督機關提起訴願"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:37+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "408", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "教育行政"}'::jsonb, NULL)
